import collections
from typing import List

class Solution:
    def solve(self, board: List[List[str]]) -> None:
        """
        Modifies the board in-place to capture surrounded regions.
        """
        if not board or not board[0]:
            return

        m, n = len(board), len(board[0])
        q = collections.deque()

        # Step 1: Identify and enqueue all 'O's on the border.
        # These are the 'O's that cannot be captured.
        for r in range(m):
            for c in range(n):
                # Check if current cell is an 'O' and is on the border
                if (r == 0 or r == m - 1 or c == 0 or c == n - 1) and board[r][c] == 'O':
                    q.append((r, c))

        # Step 2: Perform BFS to mark all 'O's connected to the border.
        # These 'O's are 'escapable' and will not be flipped to 'X'.
        # We use a temporary marker 'T' for these cells.
        # This step acts as the "DP transition" where we build up the 
        # set of escapable regions from base cases (border 'O's).
        while q:
            r, c = q.popleft()

            # If it's an 'O', mark it as 'T' (temporarily safe/escapable)
            # and explore its neighbors.
            if board[r][c] == 'O': 
                board[r][c] = 'T' 

                # Explore 4-directional neighbors
                for dr, dc in [(0, 1), (0, -1), (1, 0), (-1, 0)]:
                    nr, nc = r + dr, c + dc

                    # If neighbor is within bounds and is an 'O',
                    # add it to the queue to be processed.
                    if 0 <= nr < m and 0 <= nc < n and board[nr][nc] == 'O':
                        q.append((nr, nc))

        # Step 3: Final pass over the board to update cells.
        # Any remaining 'O's are truly surrounded and get flipped to 'X'.
        # 'T's are restored back to 'O's.
        for r in range(m):
            for c in range(n):
                if board[r][c] == 'O':
                    board[r][c] = 'X'  # Surrounded 'O's become 'X'
                elif board[r][c] == 'T':
                    board[r][c] = 'O'  # Escapable 'O's are restored

