def valid_sudoku(board):
    """
    Checks if a given Sudoku board is valid.

    Args:
        board: A 9x9 2D list representing the Sudoku board.
               Empty cells are represented by '.'.

    Returns:
        True if the Sudoku board is valid, False otherwise.
    """
    n = len(board)

    # Check rows
    for row in range(n):
        seen = set()
        for col in range(n):
            if board[row][col] != '.':
                if board[row][col] in seen:
                    return False
                seen.add(board[row][col])

    # Check columns
    for col in range(n):
        seen = set()
        for row in range(n):
            if board[row][col] != '.':
                if board[row][col] in seen:
                    return False
                seen.add(board[row][col])

    # Check 3x3 subgrids
    for box_row in range(0, n, 3):
        for box_col in range(0, n, 3):
            seen = set()
            for row in range(box_row, box_row + 3):
                for col in range(box_col, box_col + 3):
                    if board[row][col] != '.':
                        if board[row][col] in seen:
                            return False
                        seen.add(board[row][col])

    return True

