class LRUCache:

    def __init__(self, capacity: int):
        self.capacity = capacity
        self.cache = {}  # Dictionary to store key-value pairs
        self.queue = []   # List to maintain the order of access (LRU)

    def get(self, key: int) -> int:
        if key in self.cache:
            # Move the accessed key to the end of the queue (most recently used)
            self.queue.remove(key)
            self.queue.append(key)
            return self.cache[key]
        else:
            return -1

    def put(self, key: int, value: int) -> None:
        if key in self.cache:
            # Update the value and move the key to the end of the queue
            self.cache[key] = value
            self.queue.remove(key)
            self.queue.append(key)
        else:
            if len(self.cache) >= self.capacity:
                # Remove the least recently used key (first element in the queue)
                lru_key = self.queue.pop(0)
                del self.cache[lru_key)

            self.cache[key] = value
            self.queue.append(key)

