def combinationSum(candidates, target):
    """
    Finds all possible combinations of numbers in candidates that sum to target.

    Args:
        candidates: A list of integers representing the candidate numbers.
        target: An integer representing the target sum.

    Returns:
        A list of lists, where each inner list represents a combination.
    """
    dp = [[] for _ in range(target + 1)]
    dp[0] = [[]]

    for i in range(target + 1):
        if dp[i]:
            for candidate in candidates:
                if i + candidate <= target:
                    for combination in dp[i]:
                        dp[i + candidate].append(combination + [candidate])

    return dp[target]
